	@Test
	void killSwitchDisablesOnlyDphypWhileUnifiedSearchRemainsComplete() {
		LmdbDphypJoinCandidate dphypCandidate = new LmdbDphypJoinCandidate(
				JoinTree.join(JoinTree.join(JoinTree.factor(10), JoinTree.factor(11)), JoinTree.factor(12)),
				2.0d, 7.0d, "HASH", false);
		JoinSearchContributor dphyp = new LmdbDphypJoinSearchContributor(ignored -> Optional.of(dphypCandidate));
		JoinSearchService service = new JoinSearchService(
				List.of(dphyp, new ExhaustiveLegalJoinSearchContributor(3)));
		JoinSearchRequest request = JoinSearchRequest.complete(regionWithRepeatedMemoGroup(), canonicalCostModel());

		System.setProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY, "true");
		List<JoinSearchCandidate> enabledCandidates = new ArrayList<>();
		JoinSearchResult enabled = service.search(request, enabledCandidates::add);

		System.setProperty(LmdbHypergraphJoinPlanner.DPHYP_PROPERTY, "false");
		List<JoinSearchCandidate> disabledCandidates = new ArrayList<>();
		JoinSearchResult disabled = service.search(request, disabledCandidates::add);

		JoinSearchResult.Attempt enabledDphyp = attempt(enabled, CONTRIBUTOR_ID);
		JoinSearchResult.Attempt disabledDphyp = attempt(disabled, CONTRIBUTOR_ID);
		JoinSearchCandidate contributed = enabledCandidates.stream()
				.filter(candidate -> CONTRIBUTOR_ID.equals(candidate.contributorId()))
				.findFirst()
				.orElseThrow();
		assertAll(
				() -> assertEquals(JoinSearchContributor.Status.COMPLETED, enabledDphyp.outcome().status()),
				() -> assertEquals(1L, enabledDphyp.offeredCandidateCount()),
				() -> assertEquals(Set.of(10, 11, 12), Set.copyOf(contributed.tree().leafOrder()),
						"DPhyp scan positions must map to occurrence IDs even when two occurrences share a memo group"),
				() -> assertEquals(JoinSearchContributor.Status.DISABLED, disabledDphyp.outcome().status()),
				() -> assertEquals(0L, disabledDphyp.offeredCandidateCount()),
				() -> assertFalse(disabledCandidates.stream()
						.anyMatch(candidate -> CONTRIBUTOR_ID.equals(candidate.contributorId()))),
				() -> assertEquals(JoinSearchCompleteness.COMPLETE, enabled.completeness()),
				() -> assertEquals(JoinSearchCompleteness.COMPLETE, disabled.completeness()),
				() -> assertEquals(enabled.winner().orElseThrow().tree().canonicalForm(),
						disabled.winner().orElseThrow().tree().canonicalForm()),
				() -> assertEquals(enabled.winner().orElseThrow().cost(), disabled.winner().orElseThrow().cost(),
						"A private DPhyp rank must not replace the unified route's canonical cost"),
				() -> assertTrue(enabledDphyp.outcome().detail().contains("rankCost="),
						"The DPhyp rank may remain visible only as contributor diagnostics"));
	}

	@Test
	void providerMapsDphypScanPositionsThroughOccurrenceContext() {
		StatementPattern repeated = pattern("subject", "repeated", "shared");
		StatementPattern equalRepeated = repeated.clone();
		StatementPattern tail = pattern("shared", "tail", "object");
		assertEquals(repeated, equalRepeated, "The regression requires structurally equal factor templates");

		JoinRegion region = new JoinRegion(List.of(
				new JoinFactor(70, 5),
				new JoinFactor(11, 5),
				new JoinFactor(42, 6)), List.of());
		JoinSearchContext context = new JoinSearchContext(List.of(
				descriptor(42, 6, tail),
				descriptor(11, 5, equalRepeated),
				descriptor(70, 5, repeated)), Set.of(), PhysicalProperties.ANY,
				OptimizationGoal.BAG_SEMANTICS, OptimizationGoal.RowGoal.ALL,
				JoinFactorCostModel.EstimationTier.STANDARD);
		JoinSearchRequest request = new JoinSearchRequest(region, canonicalCostModel(),
				JoinSearchRequest.Mode.COMPLETE, 0L, JoinSearchDependencyStamp.EMPTY, Long.MAX_VALUE, context);
		OccurrenceCostModel lmdbCosts = new OccurrenceCostModel()
				.table("repeated", 100.0d)
				.table("tail", 2.0d);

		LmdbDphypJoinCandidate rawCandidate = LmdbHypergraphJoinPlanner.tryCandidate(request, lmdbCosts, lmdbCosts)
				.orElseThrow();
		JoinSearchService service = LmdbJoinSearchProvider.create(lmdbCosts, lmdbCosts);
		List<JoinSearchCandidate> candidates = new ArrayList<>();
		JoinSearchResult result = service.search(request, candidates::add);
		JoinSearchCandidate dphypCandidate = candidates.stream()
				.filter(candidate -> CONTRIBUTOR_ID.equals(candidate.contributorId()))
				.findFirst()
				.orElseThrow();

		assertAll(
				() -> assertEquals(JoinSearchContributor.Status.COMPLETED,
						attempt(result, CONTRIBUTOR_ID).outcome().status()),
				() -> assertEquals(3, dphypCandidate.tree().leafOrder().size()),
				() -> assertEquals(Set.of(70, 11, 42), Set.copyOf(dphypCandidate.tree().leafOrder()),
						"Equal templates and repeated memo groups must retain distinct occurrence IDs"),
				() -> assertEquals(rawCandidate.tree().canonicalForm(), dphypCandidate.tree().canonicalForm(),
						"The provider must forward the raw transparent tree without rebuilding it by TupleExpr equality"),
				() -> assertEquals(JoinSearchCompleteness.COMPLETE, result.completeness()),
				() -> assertTrue(rawCandidate.diagnostics().contains("rankCost="),
						"The raw seam exposes DPhyp rank only as diagnostics beside the JoinTree"));
	}

	@Test
	void rawCandidateHonorsRegionDependenciesAndCannotMutateFactorTemplates() {
		StatementPattern requiredTemplate = pattern("requiredSubject", "small", "shared");
		StatementPattern dependentTemplate = pattern("shared", "broad", "dependentObject");
		JoinFactorDescriptor requiredDescriptor = descriptor(10, 51, requiredTemplate);
		JoinFactorDescriptor dependentDescriptor = descriptor(12, 52, dependentTemplate);
		JoinSearchContext context = new JoinSearchContext(List.of(requiredDescriptor, dependentDescriptor), Set.of(),
				PhysicalProperties.ANY, OptimizationGoal.BAG_SEMANTICS, OptimizationGoal.RowGoal.ALL,
				JoinFactorCostModel.EstimationTier.STANDARD);
		List<JoinFactor> factors = List.of(new JoinFactor(10, 51), new JoinFactor(12, 52));
		JoinRegion unconstrainedRegion = new JoinRegion(factors, List.of());
		JoinRegion constrainedRegion = new JoinRegion(factors, List.of(new JoinDependency(12, Set.of(10))));
		MutatingDependencyRankingCostModel lmdbCosts = new MutatingDependencyRankingCostModel();

		LmdbDphypJoinCandidate unconstrained = LmdbHypergraphJoinPlanner
				.tryCandidate(request(unconstrainedRegion, context), lmdbCosts, lmdbCosts)
				.orElseThrow();
		Optional<LmdbDphypJoinCandidate> constrained = LmdbHypergraphJoinPlanner
				.tryCandidate(request(constrainedRegion, context), lmdbCosts, lmdbCosts);

		assertAll(
				() -> assertEquals(List.of(12, 10), unconstrained.tree().leafOrder(),
						"The fixture must make raw LMDB ranking prefer the dependency-violating order"),
				() -> assertTrue(constrained.isEmpty() || constrainedRegion.isLegal(constrained.orElseThrow().tree()),
						"tryCandidate must never export a tree that violates JoinRegion.requiredBefore"),
				() -> constrained.ifPresent(candidate -> assertEquals(List.of(10, 12), candidate.tree().leafOrder(),
						"A supported constrained candidate must evaluate the required occurrence first")),
				() -> assertNull(requiredTemplate.getStringMetricPlanned(MutatingDependencyRankingCostModel.MUTATION),
						"Raw search must not mutate the caller's required-factor template"),
				() -> assertNull(dependentTemplate.getStringMetricPlanned(MutatingDependencyRankingCostModel.MUTATION),
						"Raw search must not mutate the caller's dependent-factor template"),
				() -> assertNull(requiredDescriptor.tupleExprTemplate()
						.getStringMetricPlanned(MutatingDependencyRankingCostModel.MUTATION),
						"Raw search must not mutate the descriptor's retained template"),
				() -> assertNotSame(requiredDescriptor.tupleExprTemplate(), requiredDescriptor.tupleExprTemplate(),
						"Each raw-search read must receive a defensive template clone"));
	}

	private static JoinSearchRequest request(JoinRegion region, JoinSearchContext context) {
		return new JoinSearchRequest(region, canonicalCostModel(), JoinSearchRequest.Mode.COMPLETE, 0L,
				JoinSearchDependencyStamp.EMPTY, Long.MAX_VALUE, context);
	}

	private static JoinSearchResult.Attempt attempt(JoinSearchResult result, String contributorId) {
		return result.attempts()
				.stream()
				.filter(attempt -> contributorId.equals(attempt.descriptor().id()))
				.findFirst()
				.orElseThrow();
	}

	private static JoinRegion regionWithRepeatedMemoGroup() {
		return new JoinRegion(List.of(
				new JoinFactor(10, 41),
				new JoinFactor(11, 41),
				new JoinFactor(12, 42)), List.of());
	}

	private static JoinSearchCostModel canonicalCostModel() {
		return new JoinSearchCostModel() {
			@Override
			public JoinSearchEstimate estimateFactor(JoinFactor factor) {
				return switch (factor.occurrenceId()) {
				case 10, 70 -> new JoinSearchEstimate(100.0d, 8.0d);
				case 11 -> new JoinSearchEstimate(10.0d, 3.0d);
				case 12, 42 -> new JoinSearchEstimate(2.0d, 1.0d);
				default -> throw new IllegalArgumentException("unexpected occurrence " + factor.occurrenceId());
				};
			}

			@Override
			public JoinSearchEstimate estimateJoin(JoinTree left, JoinSearchCost leftCost, JoinTree right,
					JoinSearchCost rightCost) {
				double outputRows = Math.max(1.0d, leftCost.outputRows() * rightCost.outputRows() * 0.01d);
				double localWork = 2.0d * rightCost.outputRows() + leftCost.outputRows() + outputRows;
				return new JoinSearchEstimate(outputRows, localWork);
			}
		};
	}

	private static JoinFactorDescriptor descriptor(int occurrenceId, int groupId, TupleExpr factor) {
		return new JoinFactorDescriptor(occurrenceId, groupId, factor, factor.getBindingNames(),
				factor.getAssuredBindingNames(), Set.of());
	}

	private static StatementPattern pattern(String subject, String predicateLocalName, String object) {
		return new StatementPattern(new Var(subject),
				new Var("p_" + predicateLocalName, VF.createIRI("urn:test:", predicateLocalName)), new Var(object));
	}

	private static final class OccurrenceCostModel extends EvaluationStatistics implements JoinFactorCostModel {

		private final Map<String, Double> rowsByPredicate = new HashMap<>();

		private OccurrenceCostModel table(String predicateLocalName, double rows) {
			rowsByPredicate.put(predicateLocalName, rows);
			return this;
		}

		@Override
		public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, Set<String> currentlyBoundVars) {
			if (!(factor instanceof StatementPattern pattern) || !pattern.getPredicateVar().hasValue()) {
				return Optional.empty();
			}
			String predicate = ((IRI) pattern.getPredicateVar().getValue()).getLocalName();
			Double rows = rowsByPredicate.get(predicate);
			return rows == null ? Optional.empty() : Optional.of(new FactorCostEstimate(rows, rows));
		}
	}

	private static final class MutatingDependencyRankingCostModel extends EvaluationStatistics
			implements JoinFactorCostModel {

		private static final String MUTATION = "test.raw-search-mutated-template";

		@Override
		public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, Set<String> currentlyBoundVars) {
			if (!(factor instanceof StatementPattern pattern) || !pattern.getPredicateVar().hasValue()) {
				return Optional.empty();
			}
			String predicate = ((IRI) pattern.getPredicateVar().getValue()).getLocalName();
			factor.setStringMetricPlanned(MUTATION, predicate);
			boolean nested = currentlyBoundVars != null && !currentlyBoundVars.isEmpty();
			return switch (predicate) {
			case "small" -> Optional.of(new FactorCostEstimate(nested ? 0.1d : 1.0d, 1.0d));
			case "broad" -> Optional.of(new FactorCostEstimate(nested ? 1_000.0d : 100.0d, 100.0d));
			default -> Optional.empty();
			};
		}
	}
